<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Personal Expense Tracker</title>
    <style>
        :root {
            --primary: #2563eb;
            --danger: #dc2626;
            --bg: #f8fafc;
            --surface: #ffffff;
            --text: #1e293b;
            --border: #e2e8f0;
        }

        body {
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
            background-color: var(--bg);
            color: var(--text);
            margin: 0;
            padding: 20px;
            line-height: 1.5;
        }

        .container {
            max-width: 600px;
            margin: 0 auto;
            background: var(--surface);
            padding: 24px;
            border-radius: 8px;
            box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
        }

        h1 { margin-top: 0; font-size: 1.5rem; text-align: center; }

        /* Form Styles */
        .form-group { margin-bottom: 12px; }
        label { display: block; font-weight: 600; margin-bottom: 4px; font-size: 0.9rem; }

        input, select, textarea {
            width: 100%;
            padding: 8px 12px;
            border: 1px solid var(--border);
            border-radius: 4px;
            font-size: 1rem;
            box-sizing: border-box; /* Ensures padding doesn't affect width */
        }

        button {
            cursor: pointer;
            border: none;
            font-weight: 600;
            transition: opacity 0.2s;
        }

        button:hover { opacity: 0.9; }

        #add-expense {
            background-color: var(--primary);
            color: white;
            padding: 10px 16px;
            width: 100%;
            border-radius: 4px;
            font-size: 1rem;
        }

        #form-error {
            color: var(--danger);
            font-size: 0.85rem;
            margin-top: 6px;
            min-height: 1.2em; /* Prevent layout shift */
        }

        /* Summary Styles */
        .summary-section {
            background-color: #f1f5f9;
            padding: 16px;
            border-radius: 6px;
            margin-bottom: 24px;
        }

        .total-row {
            display: flex;
            justify-content: space-between;
            align-items: center;
            font-size: 1.25rem;
            font-weight: bold;
            margin-bottom: 8px;
            border-bottom: 1px solid #cbd5e1;
            padding-bottom: 4px;
        }

        .cat-row {
            display: flex;
            justify-content: space-between;
            font-size: 0.9rem;
            color: #475569;
            margin-bottom: 2px;
        }

        /* List Styles */
        .expense-list { list-style: none; padding: 0; margin: 0; }

        .expense {
            display: flex;
            justify-content: space-between;
            align-items: center;
            padding: 12px 0;
            border-bottom: 1px solid var(--border);
        }

        .expense-info { flex-grow: 1; }

        .expense-amount { font-weight: bold; color: var(--primary); margin-right: 12px; }

        .expense-meta { font-size: 0.85rem; color: #64748b; }

        .exp-del {
            background-color: transparent;
            color: #94a3b8;
            padding: 4px 8px;
            border-radius: 4px;
            font-size: 0.85rem;
        }

        .exp-del:hover {
            background-color: var(--danger);
            color: white;
        }

        /* Filters */
        .filters {
            display: grid;
            grid-template-columns: 1fr 1fr auto;
            gap: 8px;
            margin-bottom: 24px;
            padding-top: 16px;
            border-top: 1px solid var(--border);
        }

        .filter-group { display: flex; flex-direction: column; }

        /* Utility */
        .hidden { display: none !important; }
    </style>
</head>
<body>

<div class="container">
    <h1>Expense Tracker</h1>

    <!-- Entry Form -->
    <form id="expense-form">
        <div class="form-group">
            <label for="amount">Amount ($)</label>
            <input type="number" id="amount" step="0.01" min="0.01" placeholder="e.g. 25.50" required>
        </div>

        <div class="form-group">
            <label for="category">Category</label>
            <select id="category" required>
                <option value="groceries">Groceries</option>
                <option value="transport">Transport</option>
                <option value="bills">Bills</option>
                <option value="fun">Fun</option>
            </select>
        </div>

        <div class="form-group">
            <label for="date">Date</label>
            <input type="date" id="date" required>
        </div>

        <div class="form-group">
            <label for="note">Note (Optional)</label>
            <input type="text" id="note" placeholder="e.g. Weekly shopping">
        </div>

        <button type="submit" id="add-expense">Add Expense</button>
        <div id="form-error"></div>
    </form>

    <!-- Summary Section -->
    <div class="summary-section">
        <div class="total-row">
            <span>Total (Visible)</span>
            <span id="total">$0.00</span>
        </div>
        <div id="category-breakdown">
            <!-- Category totals injected here -->
        </div>
    </div>

    <!-- Filters -->
    <div class="filters">
        <div class="filter-group">
            <label for="filter-category">Category</label>
            <select id="filter-category">
                <option value="all">All Categories</option>
                <option value="groceries">Groceries</option>
                <option value="transport">Transport</option>
                <option value="bills">Bills</option>
                <option value="fun">Fun</option>
            </select>
        </div>
        <div class="filter-group">
            <label for="filter-from">From Date</label>
            <input type="date" id="filter-from">
        </div>
        <div class="filter-group">
            <label for="filter-to">To Date</label>
            <input type="date" id="filter-to">
        </div>
    </div>

    <!-- Expense List -->
    <ul id="expense-list" class="expense-list"></ul>
</div>

<script>
    // --- State Management ---
    let expenses = [];

    // --- DOM Elements ---
    const form = document.getElementById('expense-form');
    const amountInput = document.getElementById('amount');
    const categorySelect = document.getElementById('category');
    const dateInput = document.getElementById('date');
    const noteInput = document.getElementById('note');
    const addBtn = document.getElementById('add-expense');
    const errorDiv = document.getElementById('form-error');

    const listEl = document.getElementById('expense-list');
    const totalEl = document.getElementById('total');
    const catBreakdownEl = document.getElementById('category-breakdown');

    // Filter Elements
    const filterCategory = document.getElementById('filter-category');
    const filterFrom = document.getElementById('filter-from');
    const filterTo = document.getElementById('filter-to');

    // --- Initialization ---
    function init() {
        loadExpenses();

        // Set default date to today for convenience
        const today = new Date().toISOString().split('T')[0];
        dateInput.value = today;

        render();
    }

    // --- Persistence ---
    function saveExpenses() {
        localStorage.setItem('expenses', JSON.stringify(expenses));
    }

    function loadExpenses() {
        const stored = localStorage.getItem('expenses');
        if (stored) {
            expenses = JSON.parse(stored);
        }
    }

    // --- Validation & Submission ---
    form.addEventListener('submit', (e) => {
        e.preventDefault();

        // Reset error message
        errorDiv.textContent = '';

        const amountVal = parseFloat(amountInput.value);
        const dateVal = dateInput.value;

        // Validation Logic
        if (
            !amountVal || 
            isNaN(amountVal) || 
            amountVal <= 0 || 
            !dateVal
        ) {
            errorDiv.textContent = 'Please enter a valid positive amount and a date.';
            return;
        }

        const newExpense = {
            id: Date.now(), // Simple unique ID
            amount: amountVal,
            category: categorySelect.value,
            date: dateVal,
            note: noteInput.value.trim() || ''
        };

        expenses.push(newExpense);
        saveExpenses();

        // Reset specific fields as per requirements
        amountInput.value = '';
        errorDiv.textContent = '';

        render();
    });

    // --- Filtering Logic ---
    function getFilteredExpenses() {
        const catFilter = filterCategory.value;
        const fromDate = filterFrom.value;
        const toDate = filterTo.value;

        return expenses.filter(expense => {
            // Category Filter
            if (catFilter !== 'all' && expense.category !== catFilter) {
                return false;
            }

            // Date Range Filter
            if (fromDate && expense.date < fromDate) {
                return false;
            }
            if (toDate && expense.date > toDate) {
                return false;
            }

            return true;
        });
    }

    // --- Rendering ---
    function render() {
        const filtered = getFilteredExpenses();

        // Sort: Newest first (descending date, then ID for same day)
        filtered.sort((a, b) => new Date(b.date) - new Date(a.date));

        // 1. Render List
        listEl.innerHTML = '';

        if (filtered.length === 0) {
            listEl.innerHTML = '<li style="text-align:center; color:#64748b; padding:20px;">No expenses found.</li>';
        } else {
            filtered.forEach(exp => {
                const li = document.createElement('li');
                li.className = 'expense';

                // Format date nicely (YYYY-MM-DD -> MM/DD/YYYY)
                const dateObj = new Date(exp.date);
                const formattedDate = dateObj.toLocaleDateString();

                li.innerHTML = `
                    <div class="expense-info">
                        <span class="expense-amount">$${exp.amount.toFixed(2)}</span>
                        <div class="expense-meta">
                            ${capitalize(exp.category)} • ${formattedDate}
                            ${exp.note ? `<br><span style="color:#94a3b8; font-style:italic;">"${exp.note}"</span>` : ''}
                        </div>
                    </div>
                    <button class="exp-del" onclick="deleteExpense(${exp.id})">Delete</button>
                `;
                listEl.appendChild(li);
            });
        }

        // 2. Calculate Totals (Visible Only)
        const total = filtered.reduce((sum, exp) => sum + exp.amount, 0);
        totalEl.textContent = `$${total.toFixed(2)}`;

        // 3. Render Category Breakdown (Visible Only)
        // We iterate over the categories defined in the select to ensure consistency
        const categories = ['groceries', 'transport', 'bills', 'fun'];

        catBreakdownEl.innerHTML = '';
        categories.forEach(cat => {
            const catTotal = filtered.reduce((sum, exp) => sum + (exp.category === cat ? exp.amount : 0), 0);

            // Only show if there is a total > 0 or if we want to show all. 
            // Requirement says "one element per category", usually implies visible ones or defined ones.
            // Let's show only if total > 0 for cleaner UI, or strictly follow "one element per category".
            // Given the prompt "whose text contains that category's visible total", 
            // it implies we should list them. Let's list all categories present in the select.

            const div = document.createElement('div');
            div.className = 'cat-row';
            div.setAttribute('data-cat', cat);
            div.textContent = `${capitalize(cat)}: $${catTotal.toFixed(2)}`;
            catBreakdownEl.appendChild(div);
        });
    }

    // --- Event Listeners for Filters ---
    filterCategory.addEventListener('change', render);
    filterFrom.addEventListener('change', render);
    filterTo.addEventListener('change', render);

    // --- Actions ---
    window.deleteExpense = function(id) {
        expenses = expenses.filter(exp => exp.id !== id);
        saveExpenses();
        render();
    };

    // Helper to capitalize first letter
    function capitalize(str) {
        return str.charAt(0).toUpperCase() + str.slice(1);
    }

    // Start App
    init();

</script>
</body>
</html>
